import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const js = await readFile(resolve(root, 'assets/construct.js'), 'utf8');
const css = await readFile(resolve(root, 'assets/construct.css'), 'utf8');
const check = process.argv.includes('--check');

const out = resolve(root, 'src/generated/client-sdk-assets.ts');
const generated = [
  '// Generated by scripts/build-client-sdk.mjs. Do not edit directly.',
  '',
  `export const CONSTRUCT_SDK_CSS = ${JSON.stringify(css)};`,
  '',
  `export const CONSTRUCT_SDK_JS = ${JSON.stringify(js)};`,
  '',
].join('\n');

if (check) {
  const current = await readFile(out, 'utf8').catch(() => '');
  if (current !== generated) {
    console.error('Generated SDK assets are stale. Run `pnpm build:client-sdk`.');
    process.exit(1);
  }
} else {
  await mkdir(dirname(out), { recursive: true });
  await writeFile(out, generated);
}
